CREATE TABLE IF NOT EXISTS t_p61016064_digital_innovation_i.wb_case_tasks (id SERIAL PRIMARY KEY, case_id INTEGER NOT NULL, user_id INTEGER NOT NULL, title TEXT NOT NULL, description TEXT, assignee TEXT, due_date DATE, priority TEXT NOT NULL DEFAULT 'medium', status TEXT NOT NULL DEFAULT 'todo', task_type TEXT NOT NULL DEFAULT 'analysis', result_note TEXT, is_archived BOOLEAN NOT NULL DEFAULT FALSE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()); CREATE INDEX IF NOT EXISTS idx_wb_tasks_case ON t_p61016064_digital_innovation_i.wb_case_tasks(case_id);